# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
from sshtunnel import SSHTunnelForwarder

def lambda_handler(event, context):
    # SSH tunnel to remote host
    with SSHTunnelForwarder(('ssh_host', 22),
                            ssh_username="ssh_user",
                            ssh_password="ssh_pass",
                            remote_bind_address=('rds_endpoint', 3306)) as tunnel:
        
        # Connect to the MySQL database
        conn = pymysql.connect(host='localhost',
                               port=tunnel.local_bind_port,
                               user='db_user',
                               password='db_pass',
                               db='database_name')
        
        try:
            with conn.cursor() as cursor:
                # Build SQL query dynamically based on event parameters
                search_term = event['search_param'] if 'search_param' in event else ''
                
                sql = f"SELECT * FROM products WHERE productName LIKE '%{search_term}%'" 
                cursor.execute(sql)
                
                # Fetch all the rows and return as JSON response
                result = cursor.fetchall()
        
        finally:
            conn.close()
    
    return {
        'statusCode': 200,
        'body': json.dumps(result)
    }